SELECT project_name
FROM projects
WHERE team_id = (SELECT team_id FROM teams WHERE team_name = 'Team A');

SELECT * 
FROM users 
WHERE team_id = (SELECT team_id FROM projects WHERE project_id = 1);

SELECT test_case_id, change_date 
FROM test_case_history
WHERE DATE(change_date) >= DATE('now', '-7 days');

SELECT projects.project_name, test_cases.test_case_name
FROM projects
INNER JOIN test_cases ON projects.project_id = test_cases.project_id;
